// === Hitung indikator ===
const ma50 = SMA(closes, 50);
const ma200 = SMA(closes, 200);

const lastClose = closes.at(-1);
const lastMA50 = ma50.at(-1);
const lastMA200 = ma200.filter(v => v !== null).at(-1) || lastMA50;
const rsi = RSI(closes, 14);

// === Tentukan sinyal ===
let signal = "⚪ Tidak ada sinyal saat ini";
if (rsi && rsi < 30) signal = "🔵 RSI Oversold (Potensi Buy)";
else if (rsi && rsi > 70) signal = "🔴 RSI Overbought (Potensi Sell)";
else if (lastMA50 > lastMA200) signal = "🟢 Golden Cross (Buy Signal)";
else if (lastMA50 < lastMA200) signal = "🔻 Death Cross (Sell Signal)";

// === Return hasil ===
return [{
  json: {
    symbol: data.meta.symbol || "BTC-USD",
    lastClose,
    rsi: rsi ? rsi.toFixed(2) : null,
    ma50: lastMA50 ? lastMA50.toFixed(2) : null,
    ma200: lastMA200 ? lastMA200.toFixed(2) : null,
    signal
  }
}];
